import { test, expect } from '@playwright/test';

test('Amazon SG backpack image loads', async ({ page }) => {
  // 1. Launch browser → Amazon SG
  await page.goto('https://www.amazon.sg/', { waitUntil: 'domcontentloaded' });

  // 2. Search for "backpack"
  const searchBox = page.locator('input[name="field-keywords"]');
  await expect(searchBox).toBeVisible();
  await searchBox.fill('backpack');
  await page.locator('input#nav-search-submit-button').click();

  // 3. Open first product
  // Wait for search results to load
  const firstProductLink = page.locator('a[href*="/dp/"]').first();
  await expect(firstProductLink).toBeVisible({ timeout: 10000 });
  await firstProductLink.click();

  // 4. Validate product image is loaded (img not broken)
  // Wait for product image to be visible
  const productImage = page.locator('img[data-a-dynamic-image]');
  await expect(productImage).toBeVisible({ timeout: 10000 });

  // Check that the image has loaded and is not broken
  const imageLoaded = await productImage.evaluate((img: HTMLImageElement) => {
    return img.complete && img.naturalWidth > 0;
  });
  expect(imageLoaded).toBe(true);

  // 5. Close browser (handled automatically by Playwright)
});
